ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?difficulty_level WHERE {
  ?reviews a :Reviews .
  ?reviews p:difficulty_level ?difficulty_level .
  ?reviews p:hikes ?hikes_f .
  FILTER(STR(?hikes_f) = "Waterfall loop")
} }
  component_2: { SELECT ?customer_review WHERE {
  ?reviews a :Reviews .
  ?reviews p:customer_review ?customer_review .
  ?reviews p:hikes ?hikes_f .
  FILTER(STR(?hikes_f) = "Waterfall loop")
} }
  full: { SELECT ?customer_review ?difficulty_level WHERE {
  ?reviews a :Reviews .
  ?reviews p:customer_review ?customer_review .
  ?reviews p:difficulty_level ?difficulty_level .
  ?reviews p:hikes ?hikes_f .
  FILTER(STR(?hikes_f) = "Waterfall loop")
} }
}

